  1→<%# ── Waiting for login ── %>
  2→<div class="bg-white border border-gray-200 rounded-lg p-6 mb-6">
  3→  <div class="flex items-center gap-2 mb-4">
  4→    <span id="status-dot" class="inline-block w-2 h-2 rounded-full bg-yellow-500 animate-pulse"></span>
  5→    <h2 class="text-lg font-semibold text-gray-900">Connecting to Tailscale</h2>
  6→  </div>
  7→
  8→  <%# ── Progress steps ── %>
  9→  <div class="space-y-3 mb-6">
 10→    <div id="step-starting" class="flex items-center gap-3 text-sm">
 11→      <span class="step-icon w-5 h-5 rounded-full bg-blue-500 flex items-center justify-center">
 12→        <svg class="w-3 h-3 text-white animate-spin" fill="none" viewBox="0 0 24 24">
 13→          <circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"></circle>
 14→          <path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"></path>
 15→        </svg>
 16→      </span>
 17→      <span class="step-text text-gray-700 font-medium">Starting sidecar container...</span>
 18→    </div>
 19→
 20→    <div id="step-url" class="flex items-center gap-3 text-sm">
 21→      <span class="step-icon w-5 h-5 rounded-full bg-gray-200 flex items-center justify-center">
 22→        <span class="w-1.5 h-1.5 rounded-full bg-gray-400"></span>
 23→      </span>
 24→      <span class="step-text text-gray-400">Waiting for login URL...</span>
 25→    </div>
 26→
 27→    <div id="step-auth" class="flex items-center gap-3 text-sm">
 28→      <span class="step-icon w-5 h-5 rounded-full bg-gray-200 flex items-center justify-center">
 29→        <span class="w-1.5 h-1.5 rounded-full bg-gray-400"></span>
 30→      </span>
 31→      <span class="step-text text-gray-400">Authenticate with Tailscale</span>
 32→    </div>
 33→  </div>
 34→
 35→  <%# ── Login link (hidden until ready) ── %>
 36→  <div id="login-link" class="hidden mb-4">
 37→    <a id="login-url" href="#" target="_blank" rel="noopener"
 38→       class="inline-block px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 text-sm">
 39→      Open Tailscale Login
 40→    </a>
 41→  </div>
 42→
 43→  <%# ── Error display ── %>
 44→  <div id="login-error" class="hidden mb-4">
 45→    <p class="text-sm text-red-600 bg-red-50 border border-red-200 rounded p-3"></p>
 46→  </div>
 47→
 48→  <div class="flex gap-3">
 49→    <%= button_to "Cancel", disable_tailscale_path, method: :delete,
 50→          class: "px-4 py-2 bg-gray-200 text-gray-700 rounded hover:bg-gray-300 text-sm",
 51→          data: { turbo_submits_with: "Cancelling..." } %>
 52→  </div>
 53→</div>
 54→
 55→<script>
 56→  (function() {
 57→    var currentStatus = "starting";
 58→
 59→    function setStepActive(id) {
 60→      var el = document.getElementById(id);
 61→      if (!el) return;
 62→      el.querySelector(".step-icon").className = "step-icon w-5 h-5 rounded-full bg-blue-500 flex items-center justify-center";
 63→      el.querySelector(".step-icon").innerHTML = '<svg class="w-3 h-3 text-white animate-spin" fill="none" viewBox="0 0 24 24"><circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"></circle><path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"></path></svg>';
 64→      el.querySelector(".step-text").className = "step-text text-gray-700 font-medium";
 65→    }
 66→
 67→    function setStepDone(id) {
 68→      var el = document.getElementById(id);
 69→      if (!el) return;
 70→      el.querySelector(".step-icon").className = "step-icon w-5 h-5 rounded-full bg-green-500 flex items-center justify-center";
 71→      el.querySelector(".step-icon").innerHTML = '<svg class="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="3"><path stroke-linecap="round" stroke-linejoin="round" d="M5 13l4 4L19 7"></path></svg>';
 72→      el.querySelector(".step-text").className = "step-text text-green-700 font-medium";
 73→    }
 74→
 75→    function updateUI(data) {
 76→      if (data.status === "starting") {
 77→        setStepActive("step-starting");
 78→      } else if (data.status === "waiting_for_url") {
 79→        setStepDone("step-starting");
 80→        setStepActive("step-url");
 81→      } else if (data.status === "login_ready") {
 82→        setStepDone("step-starting");
 83→        setStepDone("step-url");
 84→        setStepActive("step-auth");
 85→        var linkDiv = document.getElementById("login-link");
 86→        var linkEl = document.getElementById("login-url");
 87→        if (linkDiv && linkEl && data.login_url) {
 88→          linkEl.href = data.login_url;
 89→          linkDiv.classList.remove("hidden");
 90→          if (!urlOpened) {
 91→            urlOpened = true;
 92→            window.open(data.login_url, "_blank", "noopener,noreferrer");
 93→          }
 94→        }
 95→      } else if (data.status === "authenticated") {
 96→        setStepDone("step-starting");
 97→        setStepDone("step-url");
 98→        setStepDone("step-auth");
 99→        clearInterval(poll);
100→        window.location.href = "<%= connected_tailscale_path %>";
101→      } else if (data.status === "error") {
102→        clearInterval(poll);
103→        var errDiv = document.getElementById("login-error");
104→        if (errDiv) {
105→          errDiv.querySelector("p").textContent = data.error;
106→          errDiv.classList.remove("hidden");
107→        }
108→      }
109→      currentStatus = data.status;
110→    }
111→
112→    var urlOpened = false;
113→
114→    var poll = setInterval(function() {
115→      fetch("<%= login_status_tailscale_path %>", { headers: { "Accept": "application/json" } })
116→        .then(function(r) { return r.json(); })
117→        .then(updateUI)
118→        .catch(function() {});
119→    }, 2000);
120→  })();
121→</script>
122→

